import React, { useState } from "react";
import {
  GoogleMap,
  LoadScript,
  Marker,
  DirectionsService,
  DirectionsRenderer
} from "@react-google-maps/api";

const containerStyle = {
  width: "100%",
  height: "450px"
};

function GoogleMapView({ origin, destination }) {

  const [directions, setDirections] = useState(null);

  const directionsCallback = (result) => {

    if (result !== null && result.status === "OK") {

      setDirections(result);

    }

  };

  if (!origin) return <p>Getting location...</p>;

  return (

    <LoadScript googleMapsApiKey="YOUR_GOOGLE_MAP_API_KEY">

      <GoogleMap
        mapContainerStyle={containerStyle}
        center={{
          lat: origin.lat,
          lng: origin.lon
        }}
        zoom={14}
      >

        <Marker
          position={{
            lat: origin.lat,
            lng: origin.lon
          }}
        />

        {destination && (

          <Marker
            position={{
              lat: destination.lat,
              lng: destination.lon
            }}
          />

        )}

        {origin && destination && (

          <DirectionsService
            options={{
              origin: {
                lat: origin.lat,
                lng: origin.lon
              },
              destination: {
                lat: destination.lat,
                lng: destination.lon
              },
              travelMode: "DRIVING"
            }}
            callback={directionsCallback}
          />

        )}

        {directions && (

          <DirectionsRenderer
            options={{
              directions: directions
            }}
          />

        )}

      </GoogleMap>

    </LoadScript>

  );

}

export default GoogleMapView;
